"use client"; import { useEffect, useState } from "react"; import PageHeader from "@/components/PageHeader"; import { farmerApi, User } from "@/lib/api"; export default function FarmersPage() { const [farmers, setFarmers] = useState<User[]>([]); useEffect(() => { farmerApi.list().then((r) => setFarmers(r.farmers)); }, []); return <><PageHeader title="Farmers directory" text="Browse seller profiles and access their listed products." /><section className="section"><div className="container"><div className="grid grid-3">{farmers.length === 0 ? <div className="empty">No farmers available.</div> : farmers.map((f) => <div key={f._id} className="card card-pad"><h3 className="title-md">{f.name}</h3><p className="muted">{f.city || "No city"} • {f.businessName || "Independent seller"}</p><p>{f.email}</p></div>)}</div></div></section></>; }
